     1→import { useState, useEffect, useCallback } from "react";
     2→import {
     3→  Dialog,
     4→  DialogContent,
     5→  DialogHeader,
     6→  DialogTitle,
     7→} from "@/components/ui/dialog";
     8→import { Button } from "@/components/ui/button";
     9→import { Input } from "@/components/ui/input";
    10→import { Label } from "@/components/ui/label";
    11→import { Textarea } from "@/components/ui/textarea";
    12→import {
    13→  Select,
    14→  SelectContent,
    15→  SelectItem,
    16→  SelectTrigger,
    17→  SelectValue,
    18→} from "@/components/ui/select";
    19→import { Tabs, TabsContent, TabsList, TabsTrigger } from "@/components/ui/tabs";
    20→import { DatePickerWithSelects } from "@/components/ui/date-picker-with-selects";
    21→import { ConfirmationModal } from "./ConfirmationModal";
    22→import { Trash2 as Trash2, Loader2 as Loader2, History as History } from "lucide-react";
    23→import { format } from "date-fns";
    24→import { ptBR } from "date-fns/locale";
    25→import { cn } from "@/lib/utils";
    26→import { toast } from "sonner";
    27→import {
    28→  Client,
    29→  Gender,
    30→  reverseGenderMapping,
    31→  genderMapping,
    32→  ClientHistory,
    33→} from "@/types/client";
    34→import {
    35→  formatCPF,
    36→  formatPhone,
    37→  validateCPF,
    38→  cleanCPF,
    39→} from "@/utils/clientHelpers";
    40→import { clientService } from "@/services/clientService";
    41→import { debounce } from "lodash";
    42→import { Salon } from "@/types/salon";
    43→
    44→interface ClientModalProps {
    45→  isOpen: boolean;
    46→  onClose: () => void;
    47→  client?: Client | null;
    48→  onSave: (client: any) => void;
    49→  onDelete?: (clientId: string) => void;
    50→  selectedSalon?: Salon;
    51→}
    52→
    53→export function ClientModal({
    54→  isOpen,
    55→  onClose,
    56→  client,
    57→  onSave,
    58→  onDelete,
    59→  selectedSalon,
    60→}: ClientModalProps) {
    61→  const isEditing = !!client?.id;
    62→  const [showDeleteConfirm, setShowDeleteConfirm] = useState(false);
    63→
    64→  // Estados do formulário
    65→  const [formData, setFormData] = useState<any>({
    66→    fullName: "",
    67→    cpf: "",
    68→    birthDate: undefined,
    69→    gender: "",
    70→    phone: "",
    71→    email: "",
    72→    instagram: "",
    73→    observations: "",
    74→    address: {
    75→      street: "",
    76→      number: "",
    77→      complement: "",
    78→      neighborhood: "",
    79→      city: "",
    80→      state: "",
    81→      zipCode: "",
    82→    },
    83→    tags: [],
    84→    preferredProfessionalId: "",
    85→  });
    86→
    87→  // Estados de validação
    88→  const [errors, setErrors] = useState<Record<string, string>>({});
    89→  const [checkingCpf, setCheckingCpf] = useState(false);
    90→  const [cpfExists, setCpfExists] = useState(false);
    91→
    92→  // Estados para histórico
    93→  const [clientHistory, setClientHistory] = useState<ClientHistory | null>(
    94→    null
    95→  );
    96→  const [loadingHistory, setLoadingHistory] = useState(false);
    97→  const [activeTab, setActiveTab] = useState<"info" | "history">("info");
    98→
    99→  // Preencher dados quando em modo edição
   100→  useEffect(() => {
   101→    if (client && isEditing) {
   102→      const genderValue = client.gender
   103→        ? genderMapping[client.gender] || client.gender
   104→        : "";
   105→      setFormData({
   106→        fullName: client.name || "",
   107→        cpf: client.cpf || "",
   108→        birthDate: client.birthDate
   109→          ? new Date(client.birthDate + "T12:00:00")
   110→          : undefined,
   111→        gender: genderValue,
   112→        phone: client.phone || "",
   113→        email: client.email || "",
   114→        instagram: client.instagram || "",
   115→        observations: client.notes || "",
   116→        address: client.address || {
   117→          street: "",
   118→          number: "",
   119→          complement: "",
   120→          neighborhood: "",
   121→          city: "",
   122→          state: "",
   123→          zipCode: "",
   124→        },
   125→        tags: client.tags || [],
   126→        preferredProfessionalId: client.preferredProfessionalId || "",
   127→      });
   128→    } else {
   129→      // Limpar formulário em modo criação
   130→      setFormData({
   131→        fullName: "",
   132→        cpf: "",
   133→        birthDate: undefined,
   134→        gender: "",
   135→        phone: "",
   136→        email: "",
   137→        instagram: "",
   138→        observations: "",
   139→        address: {
   140→          street: "",
   141→          number: "",
   142→          complement: "",
   143→          neighborhood: "",
   144→          city: "",
   145→          state: "",
   146→          zipCode: "",
   147→        },
   148→        tags: [],
   149→        preferredProfessionalId: "",
   150→      });
   151→    }
   152→    setErrors({});
   153→    setCpfExists(false);
   154→    setClientHistory(null);
   155→    setActiveTab("info");
   156→  }, [client, isEditing, isOpen]);
   157→
   158→  // Fetch client history when tab changes to history
   159→  useEffect(() => {
   160→    const fetchHistory = async (): Promise<void> => {
   161→      if (activeTab === "history" && client?.id && !clientHistory) {
   162→        setLoadingHistory(true);
   163→        try {
   164→          const history = await clientService.getHistory(client.id);
   165→          setClientHistory(history);
   166→        } catch {
   167→          toast.error("Erro ao carregar histórico do cliente");
   168→        } finally {
   169→          setLoadingHistory(false);
   170→        }
   171→      }
   172→    };
   173→
   174→    fetchHistory();
   175→  }, [activeTab, client?.id, clientHistory]);
   176→
   177→  // Debounced CPF check
   178→  const checkCpfAvailability = useCallback(
   179→    debounce(async (cpf: string) => {
   180→      if (!cpf || cpf.length < 14) return;
   181→
   182→      const cleanedCpf = cleanCPF(cpf);
   183→      if (!validateCPF(cleanedCpf)) return;
   184→
   185→      // Don't check if editing and CPF hasn't changed
   186→      if (isEditing && client?.cpf === cleanedCpf) return;
   187→
   188→      try {
   189→        setCheckingCpf(true);
   190→        const response = await clientService.checkCpf(cleanedCpf);
   191→
   192→        if (response.exists) {
   193→          if (!isEditing || response.clientId !== client?.id) {
   194→            setCpfExists(true);
   195→            setErrors((prev) => ({
   196→              ...prev,
   197→              cpf: `O cpf já está em uso.`,
   198→            }));
   199→          }
   200→        } else {
   201→          setCpfExists(false);
   202→          setErrors((prev) => ({ ...prev, cpf: "" }));
   203→        }
   204→      } catch {
   205→        setCpfExists(false);
   206→      } finally {
   207→        setCheckingCpf(false);
   208→      }
   209→    }, 800),
   210→    [isEditing, client]
   211→  );
   212→
   213→  // Função para validar email
   214→  const validateEmail = (email: string): boolean => {
   215→    const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
   216→    return emailRegex.test(email);
   217→  };
   218→
   219→  // Handle CPF change
   220→  const handleCpfChange = (value: string): void => {
   221→    const formatted = formatCPF(value);
   222→    handleFieldChange("cpf", formatted);
   223→
   224→    if (formatted.length === 14) {
   225→      checkCpfAvailability(formatted);
   226→    }
   227→  };
   228→
   229→  // Função para validar formulário
   230→  const validateForm = (): boolean => {
   231→    const newErrors: Record<string, string> = {};
   232→
   233→    if (!formData.fullName.trim()) {
   234→      newErrors.fullName = "Nome completo é obrigatório";
   235→    }
   236→
   237→    if (formData.cpf) {
   238→      const cleanedCpf = cleanCPF(formData.cpf);
   239→      if (!validateCPF(cleanedCpf)) {
   240→        newErrors.cpf = "CPF inválido";
   241→      } else if (cpfExists) {
   242→        newErrors.cpf = "CPF já cadastrado";
   243→      }
   244→    }
   245→
   246→    if (!formData.phone.trim()) {
   247→      newErrors.phone = "Telefone é obrigatório";
   248→    }
   249→
   250→    if (formData.email && !validateEmail(formData.email)) {
   251→      newErrors.email = "Formato de email inválido";
   252→    }
   253→
   254→    setErrors(newErrors);
   255→    return Object.keys(newErrors).length === 0;
   256→  };
   257→
   258→  // Handler para mudanças nos campos
   259→  const handleFieldChange = (
   260→    field: string,
   261→    value: string | Date | undefined
   262→  ): void => {
   263→    setFormData((prev: typeof formData) => ({
   264→      ...prev,
   265→      [field]: value,
   266→    }));
   267→
   268→    // Limpar erro do campo quando o usuário começar a digitar
   269→    if (errors[field]) {
   270→      setErrors((prev) => ({
   271→        ...prev,
   272→        [field]: "",
   273→      }));
   274→    }
   275→  };
   276→
   277→  // Handler para salvar
   278→  const handleSave = (): void => {
   279→    if (!validateForm()) {
   280→      toast.error("Por favor, corrija os erros no formulário");
   281→      return;
   282→    }
   283→
   284→    // Transform gender back to enum value
   285→    const saveData = {
   286→      name: formData.fullName,
   287→      email: formData.email,
   288→      phone: formData.phone,
   289→      cpf: formData.cpf ? cleanCPF(formData.cpf) : undefined,
   290→      birthDate: formData.birthDate,
   291→      gender: formData.gender
   292→        ? reverseGenderMapping[formData.gender] || formData.gender
   293→        : undefined,
   294→      address: formData.address,
   295→      notes: formData.observations,
   296→      tags: formData.tags,
   297→      preferredProfessionalId: formData.preferredProfessionalId,
   298→      instagram: formData.instagram,
   299→      active: true,
   300→    };
   301→
   302→    onSave(saveData);
   303→  };
   304→
   305→  // Handler para exclusão
   306→  const handleDelete = (): void => {
   307→    if (client?.id && onDelete) {
   308→      onDelete(client.id);
   309→      setShowDeleteConfirm(false);
   310→      onClose();
   311→    }
   312→  };
   313→
   314→  const title = isEditing
   315→    ? "Editar Dados do Cliente"
   316→    : "Cadastrar Novo Cliente";
   317→  const saveButtonText = isEditing ? "Salvar Alterações" : "Salvar Cliente";
   318→
   319→  return (
   320→    <>
   321→      <Dialog open={isOpen} onOpenChange={onClose}>
   322→        <DialogContent className="w-[95vw] md:max-w-2xl max-h-[90vh] md:max-h-[85vh] flex flex-col p-0 gap-0 rounded-xl md:rounded-lg border-none shadow-2xl overflow-hidden"> {/* RESP: Dimensões dinâmicas e arredondamento ampliado no mobile */}
   323→          <DialogHeader className="sticky top-0 z-10 bg-background px-4 pt-4 pb-3 border-b shrink-0"> {/* RESP: Header fixo no topo com borda */}
   324→            <DialogTitle className="text-base md:text-lg font-semibold">{title}</DialogTitle> {/* RESP: Ajuste de tamanho de fonte responsivo */}
   325→          </DialogHeader>
   326→
   327→          <div className="flex-1 overflow-y-auto px-4 py-4 custom-scrollbar"> {/* RESP: Área de conteúdo com scroll interno e padding reduzido */}
   328→            <Tabs
   329→              value={activeTab}
   330→              onValueChange={(v) => setActiveTab(v as "info" | "history")}
   331→              className="w-full"
   332→            >
   333→              {isEditing && (
   334→                <TabsList className="grid w-full grid-cols-2 mb-6">
   335→                  <TabsTrigger value="info" className="h-10">Informações</TabsTrigger>
   336→                  <TabsTrigger value="history" className="h-10">
   337→                    <History className="w-4 h-4 mr-2" />
   338→                    Histórico
   339→                  </TabsTrigger>
   340→                </TabsList>
   341→              )}
   342→
   343→              <TabsContent value="info" className="space-y-6 mt-0">
   344→                {/* Nome Completo */}
   345→                <div className="flex flex-col gap-1"> {/* RESP: Label acima do input conforme padrão */}
   346→                  <Label htmlFor="fullName" className="text-sm font-medium">
   347→                    Nome Completo <span className="text-destructive">*</span>
   348→                  </Label>
   349→                  <Input
   350→                    id="fullName"
   351→                    value={formData.fullName}
   352→                    onChange={(e) =>
   353→                      handleFieldChange("fullName", e.target.value)
   354→                    }
   355→                    placeholder="Digite o nome completo"
   356→                    className={cn("salon-input w-full", errors.fullName && "border-destructive")}
   357→                  />
   358→                  {errors.fullName && (
   359→                    <p className="text-destructive text-xs mt-1">{errors.fullName}</p>
   360→                  )}
   361→                </div>
   362→
   363→                {/* Grid Responsivo - CPF e Nascimento */}
   364→                <div className="grid grid-cols-1 md:grid-cols-2 gap-4"> {/* RESP: Grid 1 col no mobile, 2 no desktop */}
   365→                  {/* CPF */}
   366→                  <div className="flex flex-col gap-1">
   367→                    <Label htmlFor="cpf" className="text-sm font-medium">CPF</Label>
   368→                    <div className="relative">
   369→                      <Input
   370→                        id="cpf"
   371→                        value={formData.cpf}
   372→                        onChange={(e) => handleCpfChange(e.target.value)}
   373→                        placeholder="000.000.000-00"
   374→                        maxLength={14}
   375→                        className={cn("salon-input w-full", errors.cpf && "border-destructive")}
   376→                      />
   377→                      {checkingCpf && (
   378→                        <Loader2 className="absolute right-3 top-1/2 -translate-y-1/2 h-4 w-4 animate-spin text-muted-foreground" />
   379→                      )}
   380→                    </div>
   381→                    {errors.cpf && (
   382→                      <p className="text-destructive text-xs mt-1">{errors.cpf}</p>
   383→                    )}
   384→                  </div>
   385→
   386→                  {/* Data de Nascimento */}
   387→                  <div className="flex flex-col gap-1">
   388→                    <Label className="text-sm font-medium">Data de Nascimento</Label>
   389→                    <DatePickerWithSelects
   390→                      date={formData.birthDate}
   391→                      onSelect={(date) => handleFieldChange("birthDate", date)}
   392→                      placeholder="Selecione a data"
   393→                      disabled={(date) =>
   394→                        date > new Date() || date < new Date("1900-01-01")
   395→                      }
   396→                      // Note: DatePickerWithSelects internal classes should ideally handle w-full
   397→                    />
   398→                  </div>
   399→                </div>
   400→
   401→                {/* Grid Responsivo - Gênero e Telefone */}
   402→                <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
   403→                  {/* Gênero */}
   404→                  <div className="flex flex-col gap-1">
   405→                    <Label className="text-sm font-medium">Gênero</Label>
   406→                    <Select
   407→                      value={formData.gender}
   408→                      onValueChange={(value) =>
   409→                        handleFieldChange("gender", value)
   410→                      }
   411→                    >
   412→                      <SelectTrigger className="salon-input w-full">
   413→                        <SelectValue placeholder="Selecione o gênero" />
   414→                      </SelectTrigger>
   415→                      <SelectContent>
   416→                        <SelectItem value="feminino">Feminino</SelectItem>
   417→                        <SelectItem value="masculino">Masculino</SelectItem>
   418→                        <SelectItem value="outro">Outro</SelectItem>
   419→                        <SelectItem value="nao_informar">
   420→                          Prefiro não informar
   421→                        </SelectItem>
   422→                      </SelectContent>
   423→                    </Select>
   424→                  </div>
   425→
   426→                  {/* Telefone */}
   427→                  <div className="flex flex-col gap-1">
   428→                    <Label htmlFor="phone" className="text-sm font-medium">
   429→                      Celular com DDD <span className="text-destructive">*</span>
   430→                    </Label>
   431→                    <Input
   432→                      id="phone"
   433→                      value={formData.phone}
   434→                      onChange={(e) =>
   435→                        handleFieldChange("phone", formatPhone(e.target.value))
   436→                      }
   437→                      placeholder="(00) 00000-0000"
   438→                      maxLength={15}
   439→                      className={cn("salon-input w-full", errors.phone && "border-destructive")}
   440→                    />
   441→                    {errors.phone && (
   442→                      <p className="text-destructive text-xs mt-1">{errors.phone}</p>
   443→                    )}
   444→                  </div>
   445→                </div>
   446→
   447→                {/* Grid Responsivo - E-mail e Instagram */}
   448→                <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
   449→                  {/* E-mail */}
   450→                  <div className="flex flex-col gap-1">
   451→                    <Label htmlFor="email" className="text-sm font-medium">E-mail</Label>
   452→                    <Input
   453→                      id="email"
   454→                      type="email"
   455→                      value={formData.email}
   456→                      onChange={(e) => handleFieldChange("email", e.target.value)}
   457→                      placeholder="cliente@email.com"
   458→                      className={cn("salon-input w-full", errors.email && "border-destructive")}
   459→                    />
   460→                    {errors.email && (
   461→                      <p className="text-destructive text-xs mt-1">{errors.email}</p>
   462→                    )}
   463→                  </div>
   464→
   465→                  {/* Instagram */}
   466→                  <div className="flex flex-col gap-1">
   467→                    <Label htmlFor="instagram" className="text-sm font-medium">Instagram</Label>
   468→                    <Input
   469→                      id="instagram"
   470→                      value={formData.instagram}
   471→                      onChange={(e) =>
   472→                        handleFieldChange("instagram", e.target.value)
   473→                      }
   474→                      placeholder="@usuario"
   475→                      className="salon-input w-full"
   476→                    />
   477→                  </div>
   478→                </div>
   479→
   480→                {/* Observações - Sempre Full Width */}
   481→                <div className="flex flex-col gap-1"> {/* RESP: Observações ocupam linha inteira */}
   482→                  <Label htmlFor="observations" className="text-sm font-medium">
   483→                    Observações internas
   484→                  </Label>
   485→                  <Textarea
   486→                    id="observations"
   487→                    value={formData.observations}
   488→                    onChange={(e) =>
   489→                      handleFieldChange(
   490→                        "observations",
   491→                        e.target.value.slice(0, 200)
   492→                      )
   493→                    }
   494→                    placeholder="Digite observações relevantes sobre o cliente..."
   495→                    maxLength={200}
   496→                    rows={4}
   497→                    className="salon-input min-h-[100px] resize-none w-full"
   498→                  />
   499→                </div>
   500→              </TabsContent>
   501→
   502→              {isEditing && (
   503→                <TabsContent value="history" className="space-y-6 mt-0">
   504→                  {loadingHistory ? (
   505→                    <div className="flex justify-center items-center h-64">
   506→                      <Loader2 className="h-8 w-8 animate-spin text-primary" />
   507→                    </div>
   508→                  ) : clientHistory ? (
   509→                    <div className="space-y-6">
   510→                      <div className="grid grid-cols-2 md:grid-cols-4 gap-3 md:gap-4">
   511→                        <div className="bg-muted/40 p-4 rounded-xl border border-border/50">
   512→                          <p className="text-[10px] uppercase font-bold text-muted-foreground mb-1">Visitas</p>
   513→                          <p className="text-2xl font-black text-primary">
   514→                            {clientHistory.statistics?.totalVisits || 0}
   515→                          </p>
   516→                        </div>
   517→                        <div className="bg-muted/40 p-4 rounded-xl border border-border/50">
   518→                          <p className="text-[10px] uppercase font-bold text-muted-foreground mb-1">Gasto</p>
   519→                          <p className="text-2xl font-black text-primary">
   520→                            R$ {(clientHistory.statistics?.totalSpent || 0).toFixed(0)}
   521→                          </p>
   522→                        </div>
   523→                        <div className="bg-muted/40 p-4 rounded-xl border border-border/50">
   524→                          <p className="text-[10px] uppercase font-bold text-muted-foreground mb-1">Ticket</p>
   525→                          <p className="text-2xl font-black text-primary">
   526→                            R$ {(clientHistory.statistics?.averageTicket || 0).toFixed(0)}
   527→                          </p>
   528→                        </div>
   529→                        <div className="bg-muted/40 p-4 rounded-xl border border-border/50">
   530→                          <p className="text-[10px] uppercase font-bold text-muted-foreground mb-1">Última</p>
   531→                          <p className="text-lg font-black text-primary leading-tight mt-1">
   532→                            {clientHistory.statistics?.lastVisit
   533→                              ? format(
   534→                                  new Date(clientHistory.statistics.lastVisit),
   535→                                  "dd/MM/yy",
   536→                                  { locale: ptBR }
   537→                                )
   538→                              : "Nunca"}
   539→                          </p>
   540→                        </div>
   541→                      </div>
   542→
   543→                      <div className="space-y-4">
   544→                        <h3 className="text-base font-semibold">Histórico recente</h3>
   545→                        {clientHistory.appointments &&
   546→                        clientHistory.appointments.length > 0 ? (
   547→                          <div className="space-y-3">
   548→                            {clientHistory.appointments.map((appointment) => (
   549→                              <div
   550→                                key={appointment.id}
   551→                                className="salon-card p-4 border-border/60"
   552→                              >
   553→                                <div className="flex justify-between items-start gap-4">
   554→                                  <div className="space-y-1">
   555→                                    <p className="font-bold text-foreground">
   556→                                      {appointment.date
   557→                                        ? format(
   558→                                            new Date(appointment.date),
   559→                                            "dd/MM/yyyy 'às' HH:mm",
   560→                                            { locale: ptBR }
   561→                                          )
   562→                                        : "N/A"}
   563→                                    </p>
   564→                                    <p className="text-xs text-muted-foreground">
   565→                                      Profissional: <span className="text-foreground font-medium">{appointment.professional?.name || "N/A"}</span>
   566→                                    </p>
   567→                                    <div className="text-xs text-muted-foreground pt-1 flex flex-wrap gap-1">
   568→                                      {appointment.services?.map((s, idx) => (
   569→                                        <span key={idx} className="bg-secondary/50 px-2 py-0.5 rounded text-primary font-medium">
   570→                                          {s?.name}
   571→                                        </span>
   572→                                      )) || "Nenhum serviço"}
   573→                                    </div>
   574→                                  </div>
   575→                                  <div className="text-right shrink-0">
   576→                                    <p className="font-black text-primary">
   577→                                      R$ {(appointment.totalAmount || 0).toFixed(2)}
   578→                                    </p>
   579→                                    <span className={cn(
   580→                                      "text-[10px] font-bold uppercase px-2 py-0.5 rounded-full ml-auto",
