     8→interface SecureCardInputProps {
     9→    onTokenHtml: (token: string, brand: string, last4: string, holder: string, exp: string) => void;
    10→    onCancel: () => void;
    11→    loading?: boolean;
    12→}
    13→
    14→export function SecureCardInput({ onTokenHtml, onCancel, loading }: SecureCardInputProps) {
    15→    const [cardData, setCardData] = useState({
    16→        number: '',
    17→        holderName: '',
    18→        expirationDate: '',
    19→        cvv: ''
    20→    });
    21→    const [processing, setProcessing] = useState(false);
    22→
    23→    const handleChange = (field: string, value: string) => {
    24→        let cleanValue = value;
    25→        if (field === 'number') cleanValue = value.replace(/\D/g, '').slice(0, 16);
    26→        if (field === 'cvv') cleanValue = value.replace(/\D/g, '').slice(0, 4);
    27→        if (field === 'expirationDate') {
    28→            cleanValue = value.replace(/\D/g, '');
    29→            if (cleanValue.length >= 2) {
    30→                cleanValue = cleanValue.slice(0, 2) + '/' + cleanValue.slice(2, 6);
    31→            }
    32→            cleanValue = cleanValue.slice(0, 7);
    33→        }
    34→        setCardData(prev => ({ ...prev, [field]: cleanValue }));
    35→    };
    36→
    37→    const detectBrand = (number: string) => {
    38→        const brands = {
    39→            visa: /^4/,
    40→            mastercard: /^5[1-5]/,
    41→            amex: /^3[47]/,
    42→            elo: /^636368|^438935|^504175|^451416|^636297|^5067|^4576|^4011/
    43→        };
    44→        for (const [key, regex] of Object.entries(brands)) {
    45→            if (regex.test(number)) return key.toUpperCase();
    46→        }
    47→        return 'UNKNOWN';
    48→    };
    49→
    50→    const handleSave = async () => {
    51→        if (!cardData.number || !cardData.holderName || !cardData.expirationDate || !cardData.cvv) {
    52→            toast.error("Preencha todos os campos do cartão.");
    53→            return;
    54→        }
    55→
    56→        setProcessing(true);
    57→        try {
    58→            // Updated Flow: Send data to Backend Proxy to tokenize (Secure)
    59→            // Backend talks to Cielo. Frontend doesn't expose keys.
    60→
    61→            // Note: Dynamic import to avoid circular dependency if any, or standard import
    62→            const { subscriptionService } = await import('@/services/subscriptionService');
    63→
    64→            const token = await subscriptionService.tokenizeCard({
    65→                cardNumber: cardData.number,
    66→                holder: cardData.holderName,
    67→                expirationDate: cardData.expirationDate,
    68→                brand: detectBrand(cardData.number)
    69→            });
    70→
    71→            if (token) {
    72→                onTokenHtml(
    73→                    token,
    74→                    detectBrand(cardData.number),
    75→                    cardData.number.slice(-4),
    76→                    cardData.holderName,
    77→                    cardData.expirationDate
    78→                );
    79→            } else {
    80→                throw new Error("Token não retornado");
    81→            }
    82→
    83→        } catch (err: any) {
    84→            console.error(err);
    85→            const msg = err.response?.data?.message || err.message || "Erro ao validar cartão.";
    86→            toast.error(msg);
    87→        } finally {
    88→            setProcessing(false);
    89→        }
    90→    };
    91→
    92→    return (
    93→        <div className="space-y-4 p-4 border rounded-lg bg-muted">
    94→            <div className="grid grid-cols-1 gap-4">
    95→                <div>
    96→                    <Label>Número do Cartão</Label>
    97→                    <Input
    98→                        placeholder="0000 0000 0000 0000"
    99→                        value={cardData.number}
   100→                        onChange={(e) => handleChange('number', e.target.value)}
   101→                        maxLength={19}
   102→                    />
   103→                </div>
   104→                <div>
   105→                    <Label>Nome Impresso</Label>
   106→                    <Input
   107→                        placeholder="COMO NO CARTAO"
   108→                        value={cardData.holderName}
   109→                        onChange={(e) => handleChange('holderName', e.target.value)}
   110→                    />
   111→                </div>
   112→                <div className="grid grid-cols-2 gap-4">
   113→                    <div>
   114→                        <Label>Validade (MM/AAAA)</Label>
   115→                        <Input
   116→                            placeholder="MM/AAAA"
   117→                            value={cardData.expirationDate}
   118→                            onChange={(e) => handleChange('expirationDate', e.target.value)}
   119→                            maxLength={7}
   120→                        />
   121→                    </div>
   122→                    <div>
   123→                        <Label>CVV</Label>
   124→                        <Input
   125→                            placeholder="123"
   126→                            value={cardData.cvv}
   127→                            onChange={(e) => handleChange('cvv', e.target.value)}
   128→                            maxLength={4}
   129→                        />
   130→                    </div>
   131→                </div>
   132→            </div>
   133→            <div className="flex justify-end gap-2 mt-4">
   134→                <Button variant="outline" onClick={onCancel} disabled={processing || loading}>
   135→                    Cancelar
   136→                </Button>
   137→                <Button onClick={handleSave} disabled={processing || loading}>
   138→                    {processing ? <Loader2 className="animate-spin mr-2 h-4 w-4" /> : null}
   139→                    Confirmar Cartão
   140→                </Button>
   141→            </div>
   142→        </div>
   143→    );
   144→}
