    89→
    90→    // Loading states
    91→    const [loadingClients, setLoadingClients] = useState(false);
    92→    const [loadingServices, setLoadingServices] = useState(false);
    93→    const [loadingProfessionals, setLoadingProfessionals] = useState(false);
    94→    const [loadingSlots, setLoadingSlots] = useState(false);
    95→    const [saving, setSaving] = useState(false);
    96→
    97→    // Estados para cadastro simplificado de cliente
    98→    const [isModoCadastroCliente, setIsModoCadastroCliente] = useState(false);
    99→    const [novoCliente, setNovoCliente] = useState({ nome: '', telefone: '' });
