   315→        }
   316→    }, [isOpen, currentStep, filteredServices, filteredProfessionals]); // Removed serviceId/professionalId to avoid loops or stale checks
   317→
   318→    // Load time slots
   319→    useEffect(() => {
   320→        const loadTimeSlots = async () => {
   321→            if (!professionalId || !serviceId || !date) {
   322→                setTimeSlots([]);
