   332→                    serviceId,
   333→                    intervalMinutes: 15,
   334→                });
   335→
   336→                const slotsData =
   337→                    availability.slots ||
   338→                    availability.availableSlots?.map(({ start, end }: any) => ({
   339→                        startTime: start,
   340→                        endTime: end,
   341→                        available: true,
   342→                    })) ||
   343→                    [];
   344→
   345→                const salonTimezone = selectedSalon?.timezone || 'America/Sao_Paulo';
   346→                const slots = slotsData.map((slot: any) => {
   347→                    const slotLabel = formatUTCToLocal(
   348→                        slot.startTime,
   349→                        salonTimezone,
   350→                        'HH:mm'
   351→                    );
   352→                    return { slot: slotLabel, available: slot.available !== false };
   353→                });
   354→
   355→                setTimeSlots(slots);
   356→
   357→                // Auto-select initial time if available
   358→                if (initialTime && slots.find((s: TimeSlot) => s.slot === initialTime && s.available)) {
   359→                    setTime(initialTime);
   360→                }
   361→            } catch (error) {
   362→                console.error('Error loading time slots:', error);
   363→                setTimeSlots([]);
   364→            } finally {
   365→                setLoadingSlots(false);
   366→            }
   367→        };
   368→
   369→        if (isOpen) {
   370→            loadTimeSlots();
   371→        }
   372→    }, [professionalId, serviceId, date, isOpen]);
   373→
   374→    // Navigation
   375→    const canProceed = (): boolean => {
   376→        switch (currentStep) {
   377→            case 1:
   378→                return !!clientId;
   379→            case 2:
   380→                return !!serviceId;
   381→            case 3:
   382→                return !!professionalId;
   383→            case 4:
   384→                return !!date;
   385→            case 5:
   386→                return !!time && timeSlots.find((s) => s.slot === time)?.available === true;
   387→            case 6:
   388→                return true;
   389→            default:
   390→                return false;
   391→        }
   392→    };
   393→
   394→    const goNext = () => {
   395→        if (currentStep < totalSteps && canProceed()) {
   396→            setCurrentStep((s) => s + 1);
   397→        } else if (currentStep === totalSteps) {
   398→            handleConfirm();
   399→        }
   400→    };
   401→
   402→    const goBack = () => {
   403→        if (currentStep > 1) {
   404→            setCurrentStep((s) => s - 1);
   405→        }
   406→    };
   407→
   408→    // Create appointment
