   414→            const service = services.find((s) => s.id === serviceId);
   415→            if (!service || !date) return;
   416→
   417→            const salonTimezone = selectedSalon?.timezone || 'America/Sao_Paulo';
   418→            const dateStr = format(date, 'yyyy-MM-dd');
   419→            const appointmentDateTime = convertLocalToUTC(dateStr, time, salonTimezone);
   420→            const endDateTime = new Date(
   421→                appointmentDateTime.getTime() + service.duracao * 60 * 1000
   422→            );
   423→
   424→            const created = await appointmentService.create({
   425→                clientId,
