   430→                status: AppointmentStatus.SCHEDULED,
   431→            });
   432→
   433→            toast.success('Agendamento criado com sucesso!');
   434→            onSuccess?.({
   435→                id: created.id,
   436→                date: format(date, 'yyyy-MM-dd'),
