   443→            toast.error(errorMsg);
   444→        } finally {
   445→            setSaving(false);
   446→        }
   447→    };
   448→
   449→    // Filter clients by search
   450→    const filteredClients = clients.filter((client) =>
   451→        client.nome.toLowerCase().includes(clientSearch.toLowerCase()) ||
   452→        client.telefone.includes(clientSearch)
