    37→
    38→    const handleChange = (field: string, value: string) => {
    39→        let cleanValue = value;
    40→        if (field === 'number') cleanValue = value.replace(/\D/g, '').slice(0, 16);
    41→        if (field === 'cvv') cleanValue = value.replace(/\D/g, '').slice(0, 4);
    42→        if (field === 'expirationDate') {
    43→            cleanValue = value.replace(/\D/g, '');
    44→            if (cleanValue.length >= 2) {
    45→                cleanValue = cleanValue.slice(0, 2) + '/' + cleanValue.slice(2, 6);
    46→            }
    47→            cleanValue = cleanValue.slice(0, 7);
    48→        }
    49→        setCardData(prev => ({ ...prev, [field]: cleanValue }));
    50→    };
    51→
    52→    const detectBrand = (number: string) => {
    53→        const brands = {
    54→            visa: /^4/,
    55→            mastercard: /^5[1-5]/,
    56→            amex: /^3[47]/,
    57→            elo: /^636368|^438935|^504175|^451416|^636297|^5067|^4576|^4011/
    58→        };
    59→        for (const [key, regex] of Object.entries(brands)) {
    60→            if (regex.test(number)) return key.toUpperCase();
    61→        }
    62→        return 'UNKNOWN';
    63→    };
    64→
    65→    const handleSave = async () => {
