    30→
    31→export function ServiceEditForm({ serviceData, onDataChange, isNewService = false }: ServiceEditFormProps) {
    32→  const [categories, setCategories] = useState<Specialty[]>([]);
    33→  const [loadingCategories, setLoadingCategories] = useState(true);
    34→
    35→  // Load categories/specialties
    36→  useEffect(() => {
    37→    const loadCategories = async () => {
    38→      try {
    39→        const response = await specialtyService.list({ limit: 100 });
    40→        setCategories(response.data);
    41→      } catch (error) {
    42→        console.error("Error loading categories:", error);
    43→      } finally {
    44→        setLoadingCategories(false);
    45→      }
    46→    };
    47→    loadCategories();
    48→  }, []);
    49→
    50→  // Convert gross value string to number for calculations
    51→  const parseValue = (value: string): number => {
    52→    return parseFloat(value.replace(/\./g, '').replace(',', '.')) || 0;
    53→  };
    54→
    55→  // Format number to Brazilian currency string without rounding
    56→  const formatValue = (value: number): string => {
    57→    // Truncate to 2 decimal places without rounding
    58→    const truncated = Math.floor(value * 100) / 100;
    59→    return truncated.toFixed(2).replace('.', ',').replace(/\B(?=(\d{3})+(?!\d))/g, '.');
    60→  };
    61→
    62→  // Calculate admin cost percentage when fixed value changes
    63→  const updateAdminCostPercent = (fixedValue: string) => {
    64→    const price = parseValue(serviceData.basePrice);
    65→    const fixed = parseValue(fixedValue);
    66→    if (price > 0 && fixed > 0) {
    67→      const percent = (fixed / price) * 100;
    68→      onDataChange({
    69→        ...serviceData,
    70→        fixedCost: fixedValue,
    71→        administrativeCostPercentage: percent.toFixed(2).replace('.', ',')
    72→      });
    73→    } else {
    74→      onDataChange({
    75→        ...serviceData,
    76→        fixedCost: fixedValue
    77→      });
    78→    }
    79→  };
    80→
    81→  // Calculate admin cost fixed value when percentage changes
    82→  const updateAdminCostFixed = (percentValue: string) => {
    83→    const price = parseValue(serviceData.basePrice);
    84→    const percent = parseValue(percentValue);
    85→    if (price > 0 && percent > 0) {
    86→      const fixed = (price * percent) / 100;
    87→      onDataChange({
    88→        ...serviceData,
    89→        administrativeCostPercentage: percentValue,
    90→        fixedCost: formatValue(fixed)
    91→      });
    92→    } else {
    93→      onDataChange({
    94→        ...serviceData,
    95→        administrativeCostPercentage: percentValue
    96→      });
    97→    }
    98→  };
    99→
   100→  // Calculate commission fixed value when percentage changes
   101→  const updateCommissionFixed = (percentValue: string) => {
   102→    const price = parseValue(serviceData.basePrice);
   103→    const adminCost = parseValue(serviceData.fixedCost || "0");
   104→    const supplies = parseValue(serviceData.supplies || "0");
   105→    const netValue = price - adminCost - supplies;
   106→    const percent = parseValue(percentValue);
   107→    if (netValue > 0 && percent > 0) {
   108→      const fixed = (netValue * percent) / 100;
   109→      onDataChange({
   110→        ...serviceData,
   111→        baseCommissionPercent: percentValue,
   112→        baseCommissionFixed: formatValue(fixed)
   113→      });
   114→    } else {
   115→      onDataChange({
   116→        ...serviceData,
   117→        baseCommissionPercent: percentValue
   118→      });
   119→    }
   120→  };
   121→
   122→  // Calculate commission percentage when fixed value changes
   123→  const updateCommissionPercent = (fixedValue: string) => {
   124→    const price = parseValue(serviceData.basePrice);
   125→    const adminCost = parseValue(serviceData.fixedCost || "0");
   126→    const supplies = parseValue(serviceData.supplies || "0");
   127→    const netValue = price - adminCost - supplies;
   128→    const fixed = parseValue(fixedValue);
   129→    if (netValue > 0 && fixed > 0) {
   130→      const percent = (fixed / netValue) * 100;
   131→      onDataChange({
   132→        ...serviceData,
   133→        baseCommissionFixed: fixedValue,
   134→        baseCommissionPercent: percent.toFixed(2).replace('.', ',')
   135→      });
   136→    } else {
   137→      onDataChange({
   138→        ...serviceData,
   139→        baseCommissionFixed: fixedValue
   140→      });
   141→    }
   142→  };
   143→
   144→  // Calculate net value (non-editable field)
   145→  const calculateNetValue = (): string => {
   146→    const price = parseValue(serviceData.basePrice);
   147→    const adminCost = parseValue(serviceData.fixedCost || "0");
   148→    const supplies = parseValue(serviceData.supplies || "0");
   149→    const netValue = price - adminCost - supplies;
   150→    return formatValue(Math.max(0, netValue));
   151→  };
   152→
   153→  // Update net value whenever related fields change
   154→  useEffect(() => {
   155→    const newNetValue = calculateNetValue();
   156→    if (serviceData.netValue !== newNetValue) {
   157→      onDataChange({
   158→        ...serviceData,
   159→        netValue: newNetValue
   160→      });
   161→    }
   162→  }, [serviceData.basePrice, serviceData.fixedCost, serviceData.supplies]);
   163→
   164→  // Recalculate commission when net value changes
   165→  useEffect(() => {
   166→    if (serviceData.baseCommissionPercent) {
   167→      const price = parseValue(serviceData.basePrice);
   168→      const adminCost = parseValue(serviceData.fixedCost || "0");
   169→      const supplies = parseValue(serviceData.supplies || "0");
   170→      const netValue = price - adminCost - supplies;
   171→      const commissionPercent = parseValue(serviceData.baseCommissionPercent);
