   182→  }, [serviceData.basePrice, serviceData.fixedCost, serviceData.supplies, serviceData.baseCommissionPercent]);
   183→
   184→  // Generate time options from 5 minutes to 8 hours in 5-minute intervals
   185→  const timeOptions = [];
   186→  for (let minutes = 5; minutes <= 480; minutes += 5) {
   187→    const hours = Math.floor(minutes / 60);
