   189→    const label = hours > 0 
   190→      ? `${hours}h${mins > 0 ? ` ${mins}min` : ''}`
   191→      : `${mins}min`;
   192→    timeOptions.push({ value: minutes.toString(), label });
   193→  }
   194→
   195→  return (
   196→    <div className="space-y-6 w-full">
   197→      {/* Nome e Categoria */}
   198→      <div className="grid grid-cols-2 gap-4">
   199→        <div className="space-y-2">
   200→          <Label>Nome do Serviço</Label>
   201→          <Input
   202→            value={serviceData.name}
   203→            onChange={(e) => onDataChange({ ...serviceData, name: e.target.value })}
   204→            disabled={!isNewService}
   205→            className={!isNewService ? "bg-muted" : ""}
