     1→import { useState, useEffect } from "react";
     2→import { EasySalonLayout } from "@/components/layout/EasySalonLayout";
     3→import { PageHeader } from "@/components/layout/PageHeader";
     4→
     5→import { Switch } from "@/components/ui/switch";
     6→import { Input } from "@/components/ui/input";
     7→import { Label } from "@/components/ui/label";
     8→import { Button } from "@/components/ui/button";
     9→import { getSalonNavItems } from "@/config/navigation";
    10→import { useAuth } from "@/contexts/AuthContext";
    11→import { useSelectedSalon } from "@/hooks/useSelectedSalon";
    12→import { toast } from "sonner";
    13→import { salonService } from "@/services/salonService";
    14→import { OpeningHours } from "@/types/salon";
    15→import { Loader2 } from "lucide-react";
    16→
    17→interface DaySchedule {
    18→  isOpen: boolean;
    19→  openTime: string;
    20→  closeTime: string;
    21→}
    22→
    23→interface WorkingHours {
    24→  monday: DaySchedule;
    25→  tuesday: DaySchedule;
    26→  wednesday: DaySchedule;
    27→  thursday: DaySchedule;
    28→  friday: DaySchedule;
    29→  saturday: DaySchedule;
    30→  sunday: DaySchedule;
    31→}
    32→
    33→interface DayOfWeek {
    34→  key: string;
    35→  label: string;
    36→  dayOfWeek: number;
    37→}
    38→
    39→interface ErrorResponse {
    40→  response?: {
    41→    status?: number;
    42→    data?: {
    43→      message?: string;
    44→    };
    45→  };
    46→  message?: string;
    47→}
    48→
    49→const daysOfWeek: DayOfWeek[] = [
    50→  { key: "monday", label: "Segunda-feira", dayOfWeek: 1 },
    51→  { key: "tuesday", label: "Terça-feira", dayOfWeek: 2 },
    52→  { key: "wednesday", label: "Quarta-feira", dayOfWeek: 3 },
    53→  { key: "thursday", label: "Quinta-feira", dayOfWeek: 4 },
    54→  { key: "friday", label: "Sexta-feira", dayOfWeek: 5 },
    55→  { key: "saturday", label: "Sábado", dayOfWeek: 6 },
    56→  { key: "sunday", label: "Domingo", dayOfWeek: 0 },
    57→];
    58→
    59→export default function WorkingHoursPage() {
    60→  const { selectedSalon } = useSelectedSalon();
    61→  const { user } = useAuth();
    62→  const [isLoading, setIsLoading] = useState(false);
    63→  const [isSaving, setIsSaving] = useState(false);
    64→  const [retryCount, setRetryCount] = useState(0);
    65→  const MAX_RETRIES = 3;
    66→
    67→  const navItems = getSalonNavItems(user?.role || "Profissional");
    68→
    69→  const [workingHours, setWorkingHours] = useState<WorkingHours>({
    70→    monday: { isOpen: true, openTime: "09:00", closeTime: "18:00" },
    71→    tuesday: { isOpen: true, openTime: "09:00", closeTime: "18:00" },
    72→    wednesday: { isOpen: true, openTime: "09:00", closeTime: "18:00" },
    73→    thursday: { isOpen: true, openTime: "09:00", closeTime: "18:00" },
    74→    friday: { isOpen: true, openTime: "09:00", closeTime: "18:00" },
    75→    saturday: { isOpen: true, openTime: "09:00", closeTime: "17:00" },
    76→    sunday: { isOpen: false, openTime: "09:00", closeTime: "17:00" },
    77→  });
    78→
    79→  // Fetch working hours on component mount
    80→  useEffect(() => {
    81→    const loadWorkingHours = async (): Promise<void> => {
    82→      if (selectedSalon?.id) {
    83→        await fetchWorkingHours();
    84→      }
    85→    };
    86→    loadWorkingHours();
    87→  }, [selectedSalon?.id]);
    88→
    89→  const fetchWorkingHours = async (): Promise<void> => {
    90→    if (!selectedSalon?.id) return;
    91→
    92→    setIsLoading(true);
    93→    try {
    94→      const data = await salonService.getWorkingHours(selectedSalon.id);
    95→
    96→      // Convert backend format to frontend format
    97→      const convertedHours: WorkingHours = {
    98→        monday: { isOpen: false, openTime: "09:00", closeTime: "18:00" },
    99→        tuesday: { isOpen: false, openTime: "09:00", closeTime: "18:00" },
   100→        wednesday: { isOpen: false, openTime: "09:00", closeTime: "18:00" },
   101→        thursday: { isOpen: false, openTime: "09:00", closeTime: "18:00" },
   102→        friday: { isOpen: false, openTime: "09:00", closeTime: "18:00" },
   103→        saturday: { isOpen: false, openTime: "09:00", closeTime: "17:00" },
   104→        sunday: { isOpen: false, openTime: "09:00", closeTime: "17:00" },
   105→      };
   106→
   107→      data.forEach((hours: OpeningHours) => {
   108→        const dayEntry = daysOfWeek.find(
   109→          (d) => d.dayOfWeek === hours.dayOfWeek
   110→        );
   111→        if (dayEntry) {
   112→          const dayKey = dayEntry.key as keyof WorkingHours;
   113→          convertedHours[dayKey] = {
   114→            isOpen: hours.isOpen,
   115→            openTime: hours.open || "09:00",
   116→            closeTime: hours.close || "18:00",
   117→          };
   118→        }
   119→      });
   120→
   121→      setWorkingHours(convertedHours);
   122→    } catch (error: unknown) {
   123→      const err = error as ErrorResponse;
   124→      if (err?.response?.status === 404) {
   125→        toast.error("Salão não encontrado");
   126→      } else if (err?.response?.status === 401) {
   127→        toast.error("Sessão expirada. Por favor, faça login novamente");
   128→      } else if (err?.response?.status === 403) {
   129→        toast.error("Você não tem permissão para visualizar os horários");
   130→      } else if (err?.message === "Network Error" || !navigator.onLine) {
   131→        if (retryCount < MAX_RETRIES) {
   132→          toast.error(
